#!/usr/bin/env node
// Generate the Gateway API reference from the committed source documents:
//   - docs/api/mcp-tools.md  <- src/gateway-tools.ts tool catalog (+ tiers)
//   - docs/api/openapi.json  <- docs/api/http-api.md documented route table
//
// Run via `npm run docs:api` (which builds first so the dist import resolves)
// and commit the generated files. Keep mkdocs --strict green: mcp-tools.md and
// http-api.md stay in the nav; openapi.json is linked from both.
import { readFileSync, writeFileSync } from 'node:fs'
import path from 'node:path'
import { fileURLToPath, pathToFileURL } from 'node:url'

const ROOT = path.resolve(path.dirname(fileURLToPath(import.meta.url)), '..')
const PKG = JSON.parse(readFileSync(path.join(ROOT, 'package.json'), 'utf-8'))
const GENERATED_NOTE = '<!-- GENERATED by scripts/generate-api-reference.mjs — do not edit by hand. Run `npm run docs:api`. -->'
const HTTP_ONLY = process.argv.includes('--http-only')
const MIN_HTTP_ROUTE_COUNT = 150
const RESPONSE_DESCRIPTIONS = {
  200: 'Successful response',
  201: 'Created',
  202: 'Accepted for asynchronous or gated processing',
  400: 'Bad request',
  401: 'Unauthorized',
  403: 'Forbidden',
  404: 'Not found',
  409: 'Conflict',
  422: 'Validation failed',
  428: 'Precondition required',
  429: 'Rate limited or capacity full',
  413: 'Request body too large',
  502: 'Bad gateway',
  503: 'Service unavailable',
}

async function loadCatalog() {
  // Dynamic URL import: resolved at runtime from the build output so knip does
  // not statically couple this script to dist/.
  const url = pathToFileURL(path.join(ROOT, 'dist', 'gateway-tools.js')).href
  const mod = await import(url)
  return mod.buildGatewayToolCatalog()
}

async function loadRuntimeApiContract() {
  const modules = await Promise.all([
    import(pathToFileURL(path.join(ROOT, 'dist', 'daemon-routes', 'system.js')).href),
    import(pathToFileURL(path.join(ROOT, 'dist', 'daemon-routes', 'work.js')).href),
    import(pathToFileURL(path.join(ROOT, 'dist', 'daemon-routes', 'opencode.js')).href),
    import(pathToFileURL(path.join(ROOT, 'dist', 'daemon-routes', 'channels.js')).href),
  ])
  const security = await import(pathToFileURL(path.join(ROOT, 'dist', 'security.js')).href)
  const leadership = await import(pathToFileURL(path.join(ROOT, 'dist', 'daemon-leadership.js')).href)
  const { z } = await import('zod')
  const descriptors = [
    ...modules[0].SYSTEM_API_ROUTE_CONTRACTS,
    ...modules[1].WORK_API_ROUTE_CONTRACTS,
    ...modules[2].OPENCODE_API_ROUTE_CONTRACTS,
    ...modules[3].CHANNEL_API_ROUTE_CONTRACTS,
  ]
  const byOperation = new Map()
  for (const descriptor of descriptors) {
    const key = `${descriptor.method.toUpperCase()} ${descriptor.path}`
    if (byOperation.has(key)) throw new Error(`duplicate runtime API route contract: ${key}`)
    byOperation.set(key, descriptor)
  }
  return {
    byOperation,
    httpCapabilityForRequest: security.httpCapabilityForRequest,
    daemonMutationRequiresWriter: leadership.daemonMutationRequiresWriter,
    toJsonSchema: schema => withoutJsonSchemaDialect(z.toJSONSchema(schema)),
  }
}

function withoutJsonSchemaDialect(schema) {
  const { $schema: _dialect, ...openapiSchema } = schema
  return openapiSchema
}

function generateMcpToolsMarkdown(groups) {
  const total = groups.reduce((sum, group) => sum + group.tools.length, 0)
  const lines = [
    GENERATED_NOTE,
    '',
    '# MCP Tools',
    '',
    `Gateway registers ${total} \`gateway_*\` MCP tools. Tool names are registered in \`src/mcp.ts\` without the \`gateway_\` prefix; OpenCode exposes them as \`gateway_<name>\`.`,
    '',
    'Use the `gateway_catalog` tool at runtime for the reachable subset enabled by that server\'s active tier.',
    '',
    'Tools are bounded by the `GATEWAY_MCP_TOOLS` tier (`read` ⊂ `operate` ⊂ `admin`, default `operate`); the **Tier** column is the minimum tier that exposes each tool. The default `operate` surface gives the single-operator agent every day-to-day workflow tool — including the composite `gateway_plan_initiative`, `gateway_dispatch_now` (operate), and `gateway_triage` (read) — while admin/config, asset mutation, restart, restore, and delete stay opt-in behind `GATEWAY_MCP_TOOLS=admin`. See [MCP tool tiers](../operations/security.md) for the model.',
    '',
    'The machine-readable HTTP contract is published at [`openapi.json`](openapi.json).',
    '',
    'Gateway Method language maps Initiative to the `gateway_roadmap_*` tools and Issue to the `gateway_task_*` tools; those names are stable compatibility contracts and are not renamed.',
    '',
  ]
  for (const group of groups) {
    lines.push(`## ${group.title}`, '', '| Tool | Tier | Purpose |', '| --- | --- | --- |')
    for (const tool of group.tools) {
      lines.push(`| \`${tool.qualifiedName}\` | ${tool.tier} | ${tool.summary} |`)
    }
    lines.push('')
  }
  return `${lines.join('\n').trimEnd()}\n`
}

function parseRouteTable(markdown) {
  const routes = []
  let tag = 'General'
  const seen = new Set()
  for (const raw of markdown.split('\n')) {
    const heading = raw.match(/^##\s+(.+?)\s*$/)
    if (heading) { tag = heading[1]; continue }
    const cells = splitMarkdownTableRow(raw)
    if (!cells || cells.length < 3) continue
    const methods = [...cells[0].matchAll(/`(GET|POST|PATCH|PUT|DELETE)`/g)].map(match => match[1].toLowerCase())
    const rawPaths = [...cells[1].matchAll(/`([^`]+)`/g)].map(match => match[1].replace(/\\\|/g, '|'))
    if (!methods.length || !rawPaths.length) continue
    const purpose = cells.slice(2).join(' | ').replace(/`/g, '').replace(/\s+/g, ' ').trim()
    for (const method of methods) {
      for (const rawPath of rawPaths) {
        const [pathPart, queryPart] = rawPath.split('?')
        // OpenAPI path templating: :param and Express-style params -> {param}.
        const openapiPath = pathPart.replace(/:([A-Za-z0-9_]+)/g, '{$1}')
        const key = `${method} ${openapiPath}`
        if (seen.has(key)) continue
        seen.add(key)
        const pathParams = [...openapiPath.matchAll(/\{([A-Za-z0-9_]+)\}/g)].map(match => match[1])
        const queryParams = queryPart
          ? [...new Set(queryPart.split('&').map(pair => pair.split('=')[0]).filter(Boolean))]
          : []
        routes.push({ method, path: openapiPath, purpose, tag, pathParams, queryParams, queryPart })
      }
    }
  }
  return routes
}

function splitMarkdownTableRow(raw) {
  if (!raw.startsWith('|') || !raw.trimEnd().endsWith('|')) return null
  const cells = []
  let cell = ''
  const line = raw.trimEnd()
  for (let i = 1; i < line.length - 1; i += 1) {
    const ch = line[i]
    if (ch === '\\' && line[i + 1] === '|') {
      cell += '\\|'
      i += 1
      continue
    }
    if (ch === '|') {
      cells.push(cell.trim())
      cell = ''
      continue
    }
    cell += ch
  }
  cells.push(cell.trim())
  return cells
}

function generateOpenApi(routes, runtime) {
  const paths = {}
  const tags = new Map()
  for (const route of routes) {
    tags.set(route.tag, true)
    const item = (paths[route.path] ||= {})
    const key = `${route.method.toUpperCase()} ${route.path}`
    const descriptor = runtime.byOperation.get(key)
    const queryNames = new Set([
      ...route.queryParams,
      ...Object.keys(descriptor?.querySchemas || {}),
    ])
    const parameters = [
      ...route.pathParams.map(name => ({ name, in: 'path', required: true, schema: { type: 'string' } })),
      ...[...queryNames].map(name => ({
        name,
        in: 'query',
        required: queryParameterRequired(route, name),
        ...(queryParameterDescription(route, name) ? { description: queryParameterDescription(route, name) } : {}),
        schema: descriptor?.querySchemas?.[name]
          ? runtime.toJsonSchema(descriptor.querySchemas[name])
          : { type: 'string' },
      })),
    ]
    const capability = capabilityForRoute(route, runtime)
    item[route.method] = {
      summary: route.purpose,
      tags: [route.tag],
      security: securityForRoute(route, capability),
      'x-required-capability': capability,
      ...(conditionalCapabilityRules(route).length ? { 'x-conditional-capabilities': conditionalCapabilityRules(route) } : {}),
      ...(parameters.length ? { parameters } : {}),
      ...(requestBodyForRoute(route, descriptor, runtime)),
      responses: responseStatusesForRoute(route, descriptor, runtime),
    }
  }
  return {
    openapi: '3.1.0',
    info: {
      title: 'OpenCode Gateway HTTP API',
      version: PKG.version,
      description:
        'Local JSON API served by the OpenCode Gateway daemon (default http://127.0.0.1:4097), consumed by the Gateway MCP server, CLI, dashboard, and channel adapters. Generated from the documented route table in docs/api/http-api.md.\n\n' +
        'Versioning intent: routes are currently served unprefixed and are treated as v1. A future `/v1` alias prefix (keeping the unprefixed routes as back-compat aliases) is a planned additive change in the daemon router; this contract documents the v1 surface today.',
    },
    servers: [{ url: 'http://127.0.0.1:4097', description: 'Local Gateway daemon (v1, unprefixed)' }],
    components: {
      securitySchemes: {
        gatewayBearer: {
          type: 'http',
          scheme: 'bearer',
          description: 'Gateway capability token. The x-required-capability operation field names the minimum runtime capability; admin satisfies every route, and operator/asset_write satisfy read.',
        },
        whatsappSignature: {
          type: 'apiKey',
          in: 'header',
          name: 'X-Hub-Signature-256',
          description: 'Meta HMAC signature verified over the raw request body.',
        },
        whatsappVerificationToken: {
          type: 'apiKey',
          in: 'query',
          name: 'hub.verify_token',
          description: 'Meta webhook setup verification token. This query credential applies only to the GET challenge; POST delivery uses X-Hub-Signature-256 HMAC verification.',
        },
        discordSignature: {
          type: 'apiKey',
          in: 'header',
          name: 'X-Signature-Ed25519',
          description: 'Discord Ed25519 request signature; X-Signature-Timestamp is also required.',
        },
      },
    },
    tags: [...tags.keys()].map(name => ({ name })),
    paths,
  }
}

function requestBodyForRoute(route, descriptor, runtime) {
  if (!['post', 'patch', 'put', 'delete'].includes(route.method)) return {}
  if (descriptor?.requestBody === false) return {}
  if (!descriptor?.bodySchema) {
    throw new Error(`mutation route ${route.method.toUpperCase()} ${route.path} must declare bodySchema or requestBody:false`)
  }
  const schema = runtime.toJsonSchema(descriptor.bodySchema)
  return {
    requestBody: {
      required: Array.isArray(schema.required) && schema.required.length > 0,
      content: {
        'application/json': {
          schema,
        },
      },
    },
  }
}

function responseStatusesForRoute(route, descriptor, runtime) {
  const statuses = new Set(descriptor?.responses || inferredStatuses(route))
  // These failures are enforced before or around every route handler by shared
  // daemon infrastructure, so include them from runtime behavior rather than
  // repeating them in each route descriptor.
  statuses.add(403)
  if (['post', 'patch', 'put', 'delete'].includes(route.method)) {
    statuses.add(400)
    statuses.add(413)
  }
  if (runtime.daemonMutationRequiresWriter(route.method, concreteRuntimePath(route.path))) statuses.add(409)
  if (route.path === '/webhooks/discord' && route.method === 'post') statuses.add(401)
  if (route.path === '/webhooks/whatsapp' && route.method === 'post') statuses.add(503)
  const sorted = [...statuses].sort((a, b) => Number(a) - Number(b))
  return Object.fromEntries(sorted.map(status => [status, { description: RESPONSE_DESCRIPTIONS[status] || `HTTP ${status}` }]))
}

function capabilityForRoute(route, runtime) {
  return runtime.httpCapabilityForRequest({
    method: route.method,
    pathname: concreteRuntimePath(route.path),
    search: route.queryPart ? `?${route.queryPart}` : '',
  })
}

function concreteRuntimePath(openapiPath) {
  return openapiPath.replace(/\{[A-Za-z0-9_]+\}/g, 'contract-value')
}

function securityForRoute(route, capability) {
  if (capability !== 'webhook') return [{ gatewayBearer: [] }]
  if (route.path === '/webhooks/whatsapp' && route.method === 'get') return [{ whatsappVerificationToken: [] }]
  if (route.path === '/webhooks/whatsapp' && route.method === 'post') return [{ whatsappSignature: [] }]
  if (route.path === '/webhooks/discord') return [{ discordSignature: [] }]
  return [{ gatewayBearer: [] }]
}

function queryParameterRequired(route, name) {
  return route.method === 'get'
    && route.path === '/webhooks/whatsapp'
    && ['hub.mode', 'hub.verify_token', 'hub.challenge'].includes(name)
}

function queryParameterDescription(route, name) {
  if (route.method === 'get' && route.path === '/config' && name === 'redact') {
    return 'Defaults to true. Setting redact=false requires an admin bearer token and records an audit entry.'
  }
  if (route.method === 'get' && ['/events', '/evidence/export', '/runs/{id}', '/opencode/sessions', '/opencode/sessions/{id}', '/opencode/mcp'].includes(route.path) && (name === 'raw' || name === 'unredacted')) {
    return `Setting ${name}=true requires an admin bearer token.`
  }
  if (route.method === 'get' && ['/evidence/export', '/opencode/sessions/{id}', '/opencode/mcp'].includes(route.path) && name === 'redact') {
    return 'Defaults to true. Setting redact=false requires an admin bearer token.'
  }
  if (route.method === 'get' && route.path === '/opencode/sessions' && name === 'all') {
    return 'Defaults to false. Setting all=true requires an admin bearer token.'
  }
  if (route.method === 'get' && route.path === '/opencode/sessions' && name === 'gatewayOnly') {
    return 'Defaults to true. Setting gatewayOnly=false broadens the result to all OpenCode sessions and requires an admin bearer token.'
  }
  if (route.method === 'get' && route.path === '/webhooks/whatsapp') {
    if (name === 'hub.mode') return 'Meta verification mode; must be subscribe.'
    if (name === 'hub.verify_token') return 'Verification token compared in constant time with the configured WhatsApp verify token.'
    if (name === 'hub.challenge') return 'Opaque challenge echoed as the successful text response.'
  }
  return undefined
}

function conditionalCapabilityRules(route) {
  if (route.method !== 'get') return []
  const rules = []
  const add = (query, description) => rules.push({ when: { query }, requiredCapability: 'admin', description })
  if (route.path === '/config') add({ redact: false }, 'Unredacted config is admin-only and audited.')
  if (route.path === '/events') {
    add({ raw: true }, 'Raw workflow event payloads are admin-only.')
    add({ unredacted: true }, 'Unredacted workflow event payloads are admin-only.')
  }
  if (route.path === '/evidence/export') {
    add({ redact: false }, 'Unredacted evidence export is admin-only.')
    add({ unredacted: true }, 'Unredacted evidence export is admin-only.')
  }
  if (route.path === '/runs/{id}') {
    add({ raw: true }, 'Raw run payloads are admin-only.')
    add({ unredacted: true }, 'Unredacted run payloads are admin-only.')
  }
  if (route.path === '/opencode/sessions') {
    add({ all: true }, 'Listing all OpenCode sessions is admin-only.')
    add({ gatewayOnly: false }, 'Listing sessions not owned by Gateway is an admin-only expansion of the default read-scoped result.')
    add({ raw: true }, 'Raw OpenCode session rows are admin-only.')
    add({ unredacted: true }, 'Unredacted OpenCode session rows are admin-only.')
  }
  if (route.path === '/opencode/sessions/{id}') {
    add({ raw: true }, 'Raw OpenCode session details are admin-only.')
    add({ unredacted: true }, 'Unredacted OpenCode session details are admin-only.')
    add({ redact: false }, 'Unredacted OpenCode session details are admin-only.')
  }
  if (route.path === '/opencode/mcp') {
    add({ raw: true }, 'Raw OpenCode asset metadata is admin-only.')
    add({ unredacted: true }, 'Unredacted OpenCode asset metadata is admin-only.')
    add({ redact: false }, 'Unredacted OpenCode asset metadata is admin-only.')
  }
  return rules
}

function assertDocumentedMutationsHaveRuntimeContracts(routes, runtime) {
  const missing = routes
    .filter(route => ['post', 'patch', 'put', 'delete'].includes(route.method))
    .map(route => `${route.method.toUpperCase()} ${route.path}`)
    .filter(key => !runtime.byOperation.has(key))
  if (missing.length) {
    throw new Error(`documented mutation routes lack runtime API contracts:\n- ${missing.join('\n- ')}`)
  }
}

function assertHttpRouteCount(routes) {
  if (routes.length < MIN_HTTP_ROUTE_COUNT) {
    throw new Error(`parsed only ${routes.length} HTTP routes from docs/api/http-api.md; expected at least ${MIN_HTTP_ROUTE_COUNT}`)
  }
}

function assertRuntimeContractsAreDocumented(routes, runtime) {
  const documented = new Set(routes.map(route => `${route.method.toUpperCase()} ${route.path}`))
  const undocumented = [...runtime.byOperation.keys()].filter(key => !documented.has(key))
  if (undocumented.length) {
    throw new Error(`runtime API route contracts are missing from docs/api/http-api.md:\n- ${undocumented.join('\n- ')}`)
  }
}

function inferredStatuses(route) {
  const statuses = new Set([200])
  for (const status of statusesMentionedInPurpose(route.purpose)) statuses.add(status)
  if (route.pathParams.length && ['get', 'patch', 'delete'].includes(route.method)) statuses.add(404)
  if (['post', 'patch', 'put'].includes(route.method)) statuses.add(400)
  if (route.method === 'delete') statuses.add(400)
  if (/\bRequires `admin`|\brequires `admin`|\brequires `asset_write`|\brequires `operator`/i.test(route.purpose)) statuses.add(403)
  if (/human gate|approvedGateId|approval gate|Precondition/i.test(route.purpose)) statuses.add(428)
  if (/Returns `?409`?|conflict/i.test(route.purpose)) statuses.add(409)
  if (/Returns `?422`?|validation|validates/i.test(route.purpose)) statuses.add(422)
  if (/Returns `?429`?|capacity full|rate/i.test(route.purpose)) statuses.add(429)
  if (/Returns `?503`?|service unavailable|critical storage/i.test(route.purpose)) statuses.add(503)
  return statuses
}

function statusesMentionedInPurpose(purpose) {
  const matches = [...purpose.matchAll(/\b(?:returns?|returning)\s+`?([1-5][0-9][0-9])`?/gi)]
  return matches.map(match => Number(match[1]))
}

async function main() {
  const httpApi = readFileSync(path.join(ROOT, 'docs', 'api', 'http-api.md'), 'utf-8')
  const routes = parseRouteTable(httpApi)
  const runtime = await loadRuntimeApiContract()
  assertHttpRouteCount(routes)
  assertDocumentedMutationsHaveRuntimeContracts(routes, runtime)
  assertRuntimeContractsAreDocumented(routes, runtime)

  let toolCount = 0
  let groupCount = 0
  if (!HTTP_ONLY) {
    const groups = await loadCatalog()
    const mcpMarkdown = generateMcpToolsMarkdown(groups)
    writeFileSync(path.join(ROOT, 'docs', 'api', 'mcp-tools.md'), mcpMarkdown)
    toolCount = groups.reduce((sum, group) => sum + group.tools.length, 0)
    groupCount = groups.length
  }

  const openapi = generateOpenApi(routes, runtime)
  writeFileSync(path.join(ROOT, 'docs', 'api', 'openapi.json'), `${JSON.stringify(openapi, null, 2)}\n`)

  if (!HTTP_ONLY) console.log(`Generated docs/api/mcp-tools.md (${toolCount} tools, ${groupCount} groups)`)
  console.log(`Generated docs/api/openapi.json (${routes.length} operations)`)
}

main().catch(error => {
  console.error('generate-api-reference failed:', error?.message || error)
  process.exit(1)
})
